        function renumberCertRows() {
            var ind;
            $('#certDynamicTable tr').each(function(index, el) {
                $(this).children('td').first().text(index++);
                ind = index;
            });
        }

        $(document).on('click', '.removecer-tr', function() {
            $(this).parents('tr').remove();
            renumberCertRows();
            --x;
        });

        function certNumberFn(ele) {
            var idval = $(ele).closest('tr').find('.cervals').val();
            $('#CertNumber'+idval).css("background","white");
        }

        function GrainProFn(ele) {
            var idval = $(ele).closest('tr').find('.cervals').val();
            $('#GrainPro'+idval).css("background","white");
        }

        function CerUomFn(ele) {
            var idval = $(ele).closest('tr').find('.cervals').val();
            $('#select2-CerUom'+idval+'-container').parent().css({"position":"relative","z-index":"2","display":"grid","table-layout":"fixed","width":"100%","background-color":"white"});
        }

        function numofbagFn(ele) {
            var idval = $(ele).closest('tr').find('.cervals').val();
            var numofbags=$('#NumofBag'+idval).val();
            if(parseInt(numofbags)==0){
                $('#NumofBag'+idval).val("");
                $('#NumofBag'+idval).css("background",errorcolor);
                toastrMessage('error',"Zero (0) is invalid input","Error");
            }
            else if(parseInt(numofbags)>0){
                $('#NumofBag'+idval).css("background","white");
            }
        }

        function checkCertNumFn(ele) {
            var idval = $(ele).closest('tr').find('.cervals').val();
            var certnum=$('#CertNumber'+idval).val();
            var cernumcount=0;
            for(var a=1;a<=z;a++){
                var certnumloop=$('#CertNumber'+a).val();
                if(certnum==certnumloop){
                    cernumcount+=1;
                }
            }

            if(parseInt(cernumcount)>=2){
                $('#CertNumber'+idval).css("background", errorcolor);
                $('#CertNumber'+idval).val("");
                toastrMessage('error',"Certificate number is already taken","Error");
            }
        }

