        function CommTypeFn(ele) {
            var idval = $(ele).closest('tr').find('.vals').val();
            var bom=$('#BillOfMaterial').val();
            var commtype=$('#CommType'+idval).val()||0;
            var origin=$('#Origin'+idval).val()||0;
            var selectedOrigin = $('#Origin'+idval+' option:selected').text();
            var grade=$('#Grade'+idval).val()||0;
            var processtype=$('#ProcessType'+idval).val();
            var cropyear=$('#CropYear'+idval).val()||0;
            var storeval=$('#store'+idval).val()||0;
            var uom=$('#Uom'+idval).val()||0;
            var supplierdata=$('#Supplier'+idval).val();
            var grndata=$('#GrnNumber'+idval).val();
            var certnumdata=$('#CertificateNum'+idval).val();
            var prdnum=$('#ProductionNum'+idval).val();
            var floormap=$('#floormapratio'+idval).val();
            var commtypecnt=0;
            var commtypecntB=0;
            var rejcnt=0;
            for(var k=1;k<=m;k++){
                if(($('#CommType'+k).val())!=undefined){
                    if((parseInt($('#CommType'+k).val()) == parseInt(commtype)) && (parseInt($('#Origin'+k).val()) == parseInt(origin)) && (parseInt($('#Grade'+k).val()) == parseInt(grade)) && ($('#ProcessType'+k).val()==processtype) && (parseInt($('#CropYear'+k).val()) == parseInt(cropyear)) && (parseInt($('#store'+k).val()) == parseInt(storeval)) && (parseInt($('#floormapratio'+k).val()) == parseInt(floormap)) && ($('#Supplier'+k).val() == parseInt(supplierdata)) && ($('#GrnNumber'+k).val() == grndata) && (!isNaN(parseInt($('#Supplier'+k).val()))) && ($('#GrnNumber'+k).val() != null)){
                        commtypecnt+=1;
                    }
                    if((parseInt($('#CommType'+k).val()) == parseInt(commtype)) && (parseInt($('#Origin'+k).val()) == parseInt(origin)) && (parseInt($('#Grade'+k).val()) == parseInt(grade)) && ($('#ProcessType'+k).val()==processtype) && (parseInt($('#CropYear'+k).val()) == parseInt(cropyear)) && (parseInt($('#store'+k).val()) == parseInt(storeval)) && (parseInt($('#floormapratio'+k).val()) == parseInt(floormap)) && ($('#ProductionNum'+k).val()==prdnum) && ($('#CertificateNum'+k).val() == certnumdata) && ($('#CertificateNum'+k).val() != "")){
                        commtypecntB+=1;
                    }
                    if((parseInt($('#CommType'+k).val()) == parseInt(defaultrejtype)) && (parseInt($('#Origin'+k).val()) == parseInt(origin)) && (parseInt($('#Grade'+k).val()) == parseInt(grade)) && ($('#ProcessType'+k).val()==processtype) && (parseInt($('#CropYear'+k).val()) == parseInt(cropyear)) && (parseInt($('#store'+k).val()) == parseInt(storeval)) && (parseInt($('#floormapratio'+k).val()) == parseInt(floormap)) && (parseInt($('#Uom'+k).val()) == parseInt(uom))){
                        rejcnt+=1;
                    }
                }
            }

            if(parseInt(commtypecnt)<=1 && parseInt(commtypecntB)<=1 && parseInt(rejcnt)<=1){
                var defaultoption = '<option selected value=""></option>';
                $('#Origin'+idval).empty();
                var originoptions = $("#origindefault > option").clone();
                $('#Origin'+idval).append(originoptions);
                $('.typeprop'+idval).hide();

                if(parseInt(commtype)==1){
                    $("#Origin"+idval+" option[title!=1]").remove(); 
                    $('#supplierdiv'+idval).show();
                    $('#grndiv'+idval).show();
                    $('#CertificateNum'+idval).val("");
                    $('#CertificateNum'+idval).css("background","white");
                }
                else if(parseInt(commtype)==2 || parseInt(commtype)==4 || parseInt(commtype)==5 || parseInt(commtype)==6){
                    $("#Origin"+idval+" option[title!=2]").remove(); 
                    $('#productiondiv'+idval).show();
                    $('#cernumdiv'+idval).show();
                    $('#Supplier'+idval).val(null).select2({
                        placeholder:"Select Supplier here",
                        dropdownCssClass : 'commprp',
                    });
                    $('#GrnNumber'+idval).val("");
                    $('#GrnNumber'+idval).css("background","white");
                    $('#select2-Supplier'+idval+'-container').parent().css({"position":"relative","z-index":"2","display":"grid","table-layout":"fixed","width":"100%","background-color":"white"});
                }
                else if(parseInt(commtype)==3){
                    $("#Origin"+idval+" option[title!=3]").remove(); 
                    $('#productiondiv'+idval).hide();
                    $('#cernumdiv'+idval).hide();
                    $('#Supplier'+idval).val(null).select2({
                        placeholder:"Select Supplier here",
                        dropdownCssClass : 'commprp',
                    });
                    $('#GrnNumber'+idval).empty();
                    $('#ProductionNum'+idval).empty();
                    $('#CertificateNum'+idval).empty();
                    $('#select2-Supplier'+idval+'-container').parent().css({"position":"relative","z-index":"2","display":"grid","table-layout":"fixed","width":"100%","background-color":"white"});
                }

                $('#Origin'+idval).append(defaultoption);
                $('#Origin'+idval).select2
                ({
                    placeholder: "Select Commodity here",
                    dropdownCssClass : 'commprp',
                });
                $('#select2-CommType'+idval+'-container').parent().css({"position":"relative","z-index":"2","display":"grid","table-layout":"fixed","width":"100%","background-color":"white"});
                $('#select2-Origin'+idval+'-container').parent().css({"position":"relative","z-index":"2","display":"grid","table-layout":"fixed","width":"100%","background-color":"white"});
            }
            else if(parseInt(commtypecnt)>1 || parseInt(commtypecntB)>1 || parseInt(rejcnt)>1){
                $('#CommType'+idval).val(null).trigger('change').select2
                ({
                    placeholder: "Select here...",
                    minimumResultsForSearch: -1
                });
                $('#select2-CommType'+idval+'-container').parent().css({"position":"relative","z-index":"2","display":"grid","table-layout":"fixed","width":"100%","background-color":errorcolor});
                toastrMessage('error',"Type is selected with all property","Error");
            }

            if(isNaN(parseInt(storeval)) || parseInt(storeval)==0){
                $('#store'+idval).empty();
                var storeoptions = $("#storecbx > option").clone();
                var defstore = '<option selected value=""></option>';
                $('#store'+idval).append(storeoptions);
                $('#store'+idval).append(defstore);
                $('#store'+idval).select2
                ({
                    placeholder: "Select Store here",
                    dropdownCssClass : 'cusmidprp',
                });
                $('#select2-store'+idval+'-container').parent().css({"position":"relative","z-index":"2","display":"grid","table-layout":"fixed","width":"100%","background-color":"white"});
            }

            if(parseInt(commtype)==1){
                if(parseInt(commtype)>0 && parseInt(origin)>0 && grade!="" && processtype!="" && cropyear!="" && parseInt(storeval)>0 && parseInt(floormap)>0 && parseInt(uom)>0 && parseInt(supplierdata)>0 && grndata!=""){
                    calcQtyOnHand(idval);
                }
            }
            else if(parseInt(commtype)==2 || parseInt(commtype)==4|| parseInt(commtype)==5 || parseInt(commtype)==6){
                if(parseInt(commtype)>0 && parseInt(origin)>0 && grade!="" && processtype!="" && cropyear!="" && parseInt(storeval)>0 && parseInt(floormap)>0 && parseInt(uom)>0 && certnumdata!="" && prdnum!=""){
                    calcQtyOnHand(idval);
                }
            }
            else if(parseInt(commtype)==3){
                if(parseInt(commtype)>0 && parseInt(origin)>0 && grade!="" && processtype!="" && cropyear!="" && parseInt(storeval)>0 && parseInt(floormap)>0 && parseInt(uom)>0){
                    calcQtyOnHand(idval);
                }
            }
        }

