        function calcQtyOnHand(rowid){
            var commtype="";
            var origin="";
            var grade="";
            var processtype="";
            var cropyear="";
            var storeval="";
            var uom="";
            var supplierid="";
            var grnnumber="";
            var prdordernumber="";
            var certnumber="";
            var floormap="";
            var quantity=0;
            var compType=$('#CompanyType').val();
            var customersId=$('#ratioCustomerId').val();
            var cusOrOwner=0;
            var baseRecordId=0;
            var totalbalnce=0;
            var totalbalancekg=0;
            
            $.ajax({
                url: '/calcComBalance',
                type: 'POST',
                data:{
                    commtype:$('#CommType'+rowid).val(),
                    origin:$('#Origin'+rowid).val(),
                    grade:$('#Grade'+rowid).val(),
                    processtype:$('#ProcessType'+rowid).val(),
                    cropyear:$('#CropYear'+rowid).val(),
                    storeval:$('#store'+rowid).val(),
                    floormap:$('#floormapratio'+rowid).val(),
                    supplierid:$('#Supplier'+rowid).val(),
                    grnnumber:$('#GrnNumber'+rowid).val(),
                    prdordernumber:$('#ProductionNum'+rowid).val(),
                    certnumber:$('#CertificateNum'+rowid).val(),
                    uom:$('#Uom'+rowid).val(),
                    cusOrOwner:customersId,
                    baseRecordId:$('#ratioRecId').val(),
                },
                beforeSend: function() {
                    cardSection.block({
                        message:
                        '<div class="d-flex justify-content-center align-items-center"><p class="mr-50 mb-50">Loading Please Wait...</p><div class="spinner-grow spinner-grow-sm text-white" role="status"></div> </div>',
                        css: {
                        backgroundColor: 'transparent',
                        color: '#fff',
                        border: '0'
                        },
                        overlayCSS: {
                        opacity: 0.5
                        }
                    });
                },
                complete: function () { 
                    cardSection.block({
                        message:
                            '',
                            timeout: 1,
                            css: {
                            backgroundColor: '',
                            color: '',
                            border: ''
                            }, 
                    });     
                },
                success: function(data) {
                    quantity=$('#Quantity'+rowid).val()||0;
                    totalbalnce=(parseFloat(data.avbalancebag)+parseFloat(data.stockoutbag))-parseFloat(data.penstockoutbag)-parseFloat(data.avothbalancebag);
                    totalbalancekg=(parseFloat(data.avbalancekg)+parseFloat(data.stockoutkg))-parseFloat(data.penstockoutkg)-parseFloat(data.avothbalancekg);
                    totalbalnce <= 0 ? 0 : totalbalnce;
                    totalbalancekg <= 0 ? 0 : totalbalancekg;
                    $('#uomfactor'+rowid).val(data.uomfactor);
                    // $('#QtyOnHand'+rowid).val("");
                    // $('#QtyConverted'+rowid).val(""); 
                    // $('#QtyOnHandByKg'+rowid).val(""); 
                    // $('#UnitPrice'+rowid).val(""); 
                    // $('#TotalPrice'+rowid).val(""); 
                    // $('#avqtybyuom'+rowid).html(""); 
                    // $('#avqtybykg'+rowid).html(""); 
                    if(parseFloat(totalbalnce)<parseFloat(quantity)){
                        $('#QtyOnHand'+rowid).val("");
                        $('#QtyConverted'+rowid).val(""); 
                        $('#QtyOnHandByKg'+rowid).val(""); 
                        $('#UnitPrice'+rowid).val("");
                        $('#TotalPrice'+rowid).val(""); 
                        $('#Quantity'+rowid).val(""); 
                        toastrMessage('error',"Insufficent quantity","Error");
                    }
                    else if(parseFloat(totalbalnce)>=parseFloat(quantity)){
                        $('#UnitPrice'+rowid).val(data.avcost);
                        var conquantity=parseFloat(data.uomfactor)*parseFloat(quantity);
                        $('#QtyOnHand'+rowid).val(totalbalnce);
                        $('#QtyOnHandByKg'+rowid).val(totalbalancekg);
                        $('#avqtybyuom'+rowid).html(numformat(parseFloat(totalbalnce))+" "+data.uomname);
                        $('#avqtybykg'+rowid).html(numformat(parseFloat(totalbalancekg).toFixed(2))+" KG");
                        $('#Quantity'+rowid).attr('maxlength',totalbalnce);
                    }
                }
            });
        }

        function QuantityFn(ele) {
            var idval = $(ele).closest('tr').find('.vals').val();
            var quantity=$('#Quantity'+idval).val()||0;
            var qtyonhand=$('#QtyOnHand'+idval).val()||0;
            var qtyonhandkg=$('#QtyOnHandByKg'+idval).val()||0;
