        function WeightKgFn(ele) {
            var idval = $(ele).closest('tr').find('.vals').val();
            var quantity=$('#Quantity'+idval).val()||0;
            var qtyonhand=$('#QtyOnHand'+idval).val()||0;
            var qtyonhandkg=$('#QtyOnHandByKg'+idval).val()||0;
            var unitcost=$('#UnitPrice'+idval).val()||0;
            var uomfactor=$('#uomfactor'+idval).val()||0;
            var uombagweight=$('#bagWeight'+idval).val()||0;
            var weightbykg=$('#QtyConverted'+idval).val()||0;
            
            var actualkg=0;
            var variance=0;
            var conqty=0;
            var totalcost=0;

            if(parseFloat(weightbykg)==0){
                $('#Quantity'+idval).val("");
                $('#QtyConverted'+idval).val("");
                $('#TotalPrice'+idval).val(""); 
                $('#varianceshortage'+idval).val("");
                $('#varianceoverage'+idval).val("");
                $('#varianceLbl'+idval).html("");
                toastrMessage('error',"Zero(0) is invalid input","Error");
            }
            else if(parseFloat(quantity)>0 && parseFloat(weightbykg)>0){
                $('#QtyConverted'+idval).css("background","white");
                if(parseFloat(qtyonhandkg)<parseFloat(weightbykg)){
                    $('#QtyConverted'+idval).val("");
                    $('#QtyConverted'+idval).css("background",errorcolor);
                    toastrMessage('error',"The maximum allowed quantity is "+qtyonhandkg+" KG","Error");
                }
            }
            CalculateVariance(idval);
            CalculateTotalRatioCost();
            $('#BillOfMaterial').val(1).select2();
        }

        function CalculateVariance(ids){
            var quantity=$('#Quantity'+ids).val()||0;
            var uomfactor=$('#uomfactor'+ids).val()||0;
            var uombagweight=$('#bagWeight'+ids).val()||0;
            var weightbykg=$('#QtyConverted'+ids).val()||0;
            var unitcost=$('#UnitPrice'+ids).val()||0;
            var qtyonhand=$('#UnitPrice'+ids).val()||0;
            var actualkg=parseFloat(quantity)*parseFloat(uomfactor);
            var variance=0;
            var totalcost=0;
            quantity = quantity == '' ? 0 : quantity;
            uomfactor = uomfactor == '' ? 0 : uomfactor;
            weightbykg = weightbykg == '' ? 0 : weightbykg;
            unitcost = unitcost == '' ? 0 : unitcost;
            totalcost=parseFloat(unitcost)*parseFloat(weightbykg);
            if(parseFloat(quantity)>0 && parseFloat(weightbykg)>0){
                if(parseFloat(weightbykg)>parseFloat(actualkg)){
                    variance=parseFloat(weightbykg)-parseFloat(actualkg);
                    $('#TotalPrice'+ids).val(parseFloat(totalcost).toFixed(2));
                    $('#varianceoverage'+ids).val(parseFloat(variance).toFixed(2));
                    $('#varianceshortage'+ids).val("");
                    $('#varianceLbl'+ids).html("Variance Overage: "+ numformat(parseFloat(variance).toFixed(2))+" KG");
                }
                else if(parseFloat(actualkg)>parseFloat(weightbykg)){
                    variance=parseFloat(actualkg)-parseFloat(weightbykg);
                    $('#TotalPrice'+ids).val(parseFloat(totalcost).toFixed(2));
                    $('#varianceshortage'+ids).val(parseFloat(variance).toFixed(2));
                    $('#varianceoverage'+ids).val("");
                    $('#varianceLbl'+ids).html("Variance Shortage: "+ numformat(parseFloat(variance).toFixed(2))+" KG");
                }
                else{
                    $('#varianceshortage'+ids).val("");
                    $('#varianceoverage'+ids).val("");
                    $('#varianceLbl'+ids).html("");
                }
            }
            else{
                $('#varianceshortage'+ids).val("");
                $('#varianceoverage'+ids).val("");
                $('#TotalPrice'+ids).val(""); 
                $('#varianceLbl'+ids).html("");
            }
        }

