        function UomFn(ele) {
            var idval = $(ele).closest('tr').find('.vals').val();
            var bom=$('#BillOfMaterial').val();
            var commtype=$('#CommType'+idval).val()||0;
            var origin=$('#Origin'+idval).val()||0;
            var grade=$('#Grade'+idval).val()||0;
            var processtype=$('#ProcessType'+idval).val();
            var cropyear=$('#CropYear'+idval).val()||0;
            var storeval=$('#store'+idval).val()||0;
            var uom=$('#Uom'+idval).val()||0;
            var supplierdata=$('#Supplier'+idval).val();
            var grndata=$('#GrnNumber'+idval).val();
            var certnumdata=$('#CertificateNum'+idval).val();
            var prdnum=$('#ProductionNum'+idval).val();
            var floormap=$('#floormapratio'+idval).val();
            var uomcnt=0;
            var uomcntB=0;
            var rejcnt=0;

            for(var k=1;k<=m;k++){
                if(($('#Uom'+k).val())!=undefined){
                    if((parseInt($('#CommType'+k).val()) == parseInt(commtype)) && (parseInt($('#Origin'+k).val()) == parseInt(origin)) && (parseInt($('#Grade'+k).val()) == parseInt(grade)) && ($('#ProcessType'+k).val()==processtype) && (parseInt($('#CropYear'+k).val()) == parseInt(cropyear)) && (parseInt($('#store'+k).val()) == parseInt(storeval)) && (parseInt($('#floormapratio'+k).val()) == parseInt(floormap)) && ($('#Supplier'+k).val() == parseInt(supplierdata)) && ($('#GrnNumber'+k).val() == grndata) && (!isNaN(parseInt($('#Supplier'+k).val()))) && ($('#GrnNumber'+k).val() != null)){
                        uomcnt+=1;
                    }
                    if((parseInt($('#CommType'+k).val()) == parseInt(commtype)) && (parseInt($('#Origin'+k).val()) == parseInt(origin)) && (parseInt($('#Grade'+k).val()) == parseInt(grade)) && ($('#ProcessType'+k).val()==processtype) && (parseInt($('#CropYear'+k).val()) == parseInt(cropyear)) && (parseInt($('#store'+k).val()) == parseInt(storeval)) && (parseInt($('#floormapratio'+k).val()) == parseInt(floormap)) && ($('#ProductionNum'+k).val()==prdnum) && ($('#ProductionNum'+k).val()==prdnum) && ($('#CertificateNum'+k).val() == certnumdata) && ($('#CertificateNum'+k).val() != "")){
                        uomcntB+=1;
                    }
                    if((parseInt($('#CommType'+k).val()) == parseInt(defaultrejtype)) && (parseInt($('#Origin'+k).val()) == parseInt(origin)) && (parseInt($('#Grade'+k).val()) == parseInt(grade)) && ($('#ProcessType'+k).val()==processtype) && (parseInt($('#CropYear'+k).val()) == parseInt(cropyear)) && (parseInt($('#store'+k).val()) == parseInt(storeval)) && (parseInt($('#floormapratio'+k).val()) == parseInt(floormap)) && (parseInt($('#Uom'+k).val()) == parseInt(uom))){
                        rejcnt+=1;
                    }
                }
            }

            if(parseInt(uomcnt)<=1 && parseInt(uomcntB)<=1 && parseInt(rejcnt)<=1){
                $('#select2-Uom'+idval+'-container').parent().css({"position":"relative","z-index":"2","display":"grid","table-layout":"fixed","width":"100%","background-color":"white"});
            }

            else if(parseInt(uomcnt)>1 || parseInt(uomcntB)>1 || parseInt(rejcnt)>1){
                $('#Uom'+idval).val(null).trigger('change').select2
                ({
                    placeholder: "Select Store here...",
                    dropdownCssClass : 'cusprop',
                });
                $('#select2-Uom'+idval+'-container').parent().css({"position":"relative","z-index":"2","display":"grid","table-layout":"fixed","width":"100%","background-color":errorcolor});
                toastrMessage('error',"UOM/Bag is selected with all property","Error");
            }

            if(parseInt(commtype)==1){
                if(parseInt(commtype)>0 && parseInt(origin)>0 && grade!="" && processtype!="" && cropyear!="" && parseInt(storeval)>0 && parseInt(floormap)>0 && parseInt(uom)>0 && parseInt(supplierdata)>0 && grndata!=""){
                    calcQtyOnHand(idval);
                }
            }
            else if(parseInt(commtype)==2 || parseInt(commtype)==4 || parseInt(commtype)==5 || parseInt(commtype)==6){
                if(parseInt(commtype)>0 && parseInt(origin)>0 && grade!="" && processtype!="" && cropyear!="" && parseInt(storeval)>0 && parseInt(floormap)>0 && parseInt(uom)>0 && certnumdata!=""){
                    calcQtyOnHand(idval);
                }
            }
            else if(parseInt(commtype)==3){
                if(parseInt(commtype)>0 && parseInt(origin)>0 && grade!="" && processtype!="" && cropyear!="" && parseInt(storeval)>0 && parseInt(floormap)>0 && parseInt(uom)>0){
                    calcQtyOnHand(idval);
                }
            }
        }

