                    }
                    else if (data.commerror){
                        var origin="";
                        $.each(data.origindata, function(key, value) {
                            ++key;
                            origin+= "<b>"+key+".</b> "+value.Origin;
                        });
                        $('#undocompvoidbtn').text('Undo Void');
                        $('#undocompvoidbtn').prop("disabled",false);
                        $('#undocompvoidmodal').modal('hide');
                        toastrMessage('error',"The following commodities have no available balance</br>----------------------</br>"+origin,"Error");
                    }
                    else if(data.statuserror){
                        $('#undocompvoidbtn').text('Undo Void');
                        $('#undocompvoidbtn').prop("disabled",false);
                        $('#undocompvoidmodal').modal('hide');
                        toastrMessage('error',"Production order status should be on Void","Error");
                    }
                    else if(data.success){
                        $('#undocompvoidmodal').modal('hide');
                        var oTable = $('#laravel-datatable-crud').dataTable();
                        oTable.fnDraw(false);
                        toastrMessage('success',"Successful","Success");
                    }
                }
            });
        });

