        function renumberPrepRows() {
            var ind;
            var prdbrowid=$('#prdRowIdVal').val();
            $('#prepDynamicTable tr.prdregion'+prdbrowid).each(function(index, el) {
                $(this).children('td').first().text(++index);
            });
        }

        function prepDateFn(ele) {
            var idval = $(ele).closest('tr').find('.prepvals').val();
            $('#prepDate'+idval).css("background","white");
        }

        function prepQuantityFn(ele) {
            var idval = $(ele).closest('tr').find('.prepvals').val();
            var quantity=$('#prepQuantity'+idval).val()||0;
            var qtyonhand=$('#prepQtyOnHand'+idval).val()||0;
            var prdbrowid=$('#prdRowIdVal').val();
            var prdAmountKg=$('#prdQuantityKg').val();
            var prduomname=$('#prdUomNameVal').val();
            var prdquantity=$('#prdQuantityVal').val();
            var bagweightval=$('#prepuombagweight'+idval).val()||0;
            var selecteduom="";

            $("#prepUom"+idval+" :selected").each(function() {
                selecteduom=this.text;
            });

            var uomfactor=0;
            var conqty=0;
            var totalqnt=0;
            var totalnumbag=0;
            var totalbagweight=0;
            var calcshortageacc=0;
            var calcoverageacc=0;
            if(parseFloat(quantity)<=0){
                $('#prepQuantityInKg'+idval).css("background","#efefef");
                $('#prepQuantityInKg'+idval).prop("readonly",true);
                $('#prepQuantityInKg'+idval).val("");
                $('#varianceshortage'+idval).val("");
                $('#varianceoverage'+idval).val("");
            }
            else if(parseFloat(quantity)>0){

                if(parseFloat(qtyonhand)<parseFloat(quantity)){
                    $('#prepQuantity'+idval).val("");
                    $('#prepQuantityInKg'+idval).val(""); 
                    toastrMessage('error',"The maximum allowed quantity is "+qtyonhand,"Error");
                }
                else if(parseFloat(qtyonhand)>=parseFloat(quantity)){
                    uomfactor=$('#prepuomfactor'+idval).val()||0;
                    conqty=0;
                    quantity = quantity == '' ? 0 : quantity;
                    uomfactor = uomfactor == '' ? 0 : uomfactor;
                    conqty=parseFloat(quantity)*parseFloat(uomfactor);
                    
                    $.each($('#prepDynamicTable').find('.quantityKg'+prdbrowid), function() {
                        if ($(this).val() != '' && !isNaN($(this).val())) {
                            totalqnt+= parseFloat($(this).val());
                        }
                    });

                    if(parseFloat(prdAmountKg) >= parseFloat(totalqnt)){
                        $('#prepQuantityInKg'+idval).val(""); 
                    }
                    else if(parseFloat(totalqnt)>parseFloat(prdAmountKg)){
                        $('#prepQuantity'+idval).val("");
                        $('#prepQuantityInKg'+idval).val("");
                        toastrMessage('error',"The maximum allowed quantity is "+prdquantity+" "+prduomname,"Error");
                    }
                }
                
                $('#prepQuantity'+idval).css("background","white");
                $('#prepQuantityInKg'+idval).css("background","white");
                $('#prepQuantityInKg'+idval).prop("readonly",false);
                $('#prepQuantity'+idval).attr('title', quantity+" "+selecteduom);
            }
            $('#preptotalbagweight'+idval).val(parseFloat(bagweightval)* parseFloat(quantity)); 
            CalculateCommTotal(prdbrowid);
        }

        function prepQuantityBlFn(ele) {
            var idval = $(ele).closest('tr').find('.prepvals').val();
            var quantity=$('#prepQuantity'+idval).val()||0;
            var quantitykg=$('#prepQuantityInKg'+idval).val()||0;
            var uomfactor=$('#prepuomfactor'+idval).val()||0;
            var prdbrowid=$('#prdRowIdVal').val();
            var prdAmountKg=$('#prdQuantityKg').val()||0;
            var prdBagQuantity=$('#prdQuantityVal').val()||0;
            var calcshortageacc=0;
            var calcoverageacc=0;
            var calctotaloverage=0;
            var conqty=0;
            var totalInsertedQuantity=0;
            
            quantitykg = quantitykg == '' ? 0 : quantitykg;
            prdAmountKg = prdAmountKg == '' ? 0 : prdAmountKg;

            quantity = quantity == '' ? 0 : quantity;
            uomfactor = uomfactor == '' ? 0 : uomfactor;
            conqty=parseFloat(quantity)*parseFloat(uomfactor);

            $.each($('#prepDynamicTable').find('.quantityBag'+prdbrowid), function() {
                if ($(this).val() != '' && !isNaN($(this).val())) {
                    totalInsertedQuantity+= parseFloat($(this).val());
                }
            });

            calcshortageacc= parseFloat(conqty) * (parseInt(1) - (parseFloat(shortageacc)/100));
            calcoverageacc= parseFloat(conqty) * (parseInt(1) + (parseFloat(overageacc)/100));
            calctotaloverage= parseFloat(prdAmountKg) * (parseInt(1) + (parseFloat(overageacc)/100));

            if(parseFloat(totalInsertedQuantity)>parseFloat(prdBagQuantity)){
                toastrMessage('error',"Quantity should not be greater than the defined quantity on ratio","Error");
                $('#prepQuantity'+idval).val("");
                $('#prepQuantityInKg'+idval).val("");
                $('#varianceshortage'+idval).val("");
                $('#varianceoverage'+idval).val("");
                $('#prepQuantity'+idval).css("background",errorcolor);
                $('#prepQuantityInKg'+idval).css("background",errorcolor);
            }
            CalculateCommTotal(prdbrowid);
        }

        function prepQuantityKgFn(ele) {
            var idval = $(ele).closest('tr').find('.prepvals').val();
            var quantity=$('#prepQuantity'+idval).val()||0;
            var quantitykg=$('#prepQuantityInKg'+idval).val()||0;
            var qtyonhandbag=$('#prepQtyOnHand'+idval).val()||0;
            var qtyonhandkg=$('#prepQtyOnHandKG'+idval).val()||0;
            var uomfactor=$('#prepuomfactor'+idval).val()||0;
            var prdbrowid=$('#prdRowIdVal').val();

            quantitykg = quantitykg == '' ? 0 : quantitykg;
            quantity = quantity == '' ? 0 : quantity;
            uomfactor = uomfactor == '' ? 0 : uomfactor;
            qtyonhandkg = qtyonhandkg == '' ? 0 : qtyonhandkg;

            var totalexpqnt=parseFloat(quantity)*parseFloat(uomfactor);
            var variance=parseFloat(totalexpqnt)-parseFloat(quantitykg);

            $('#varianceshortage'+idval).val("");
            $('#varianceoverage'+idval).val("");

            if(parseFloat(quantitykg)>parseFloat(qtyonhandkg)){
                toastrMessage('error',"Quantity should not be greater than the Quantity on Hand","Error");
                $('#prepQuantityInKg'+idval).val("");
                $('#prepQuantityInKg'+idval).css("background",errorcolor);
            }
            else{
                if(parseFloat(variance)>0){
                    $('#varianceshortage'+idval).val(variance.toFixed(2));
                }
                else if(parseFloat(variance)<0){
                    $('#varianceoverage'+idval).val(parseFloat(variance)*parseInt(-1).toFixed(2));
                }
                else if(parseFloat(variance)==0){
                    $('#varianceshortage'+idval).val("");
                    $('#varianceoverage'+idval).val("");
                }

                $('#prepQuantityInKg'+idval).css("background","white");
            }
            CalculateCommTotal(prdbrowid);
        }

        function prepQuantityKgBlFn(ele) {
            var idval = $(ele).closest('tr').find('.prepvals').val();
            var quantity=$('#prepQuantity'+idval).val()||0;
            var quantitykg=$('#prepQuantityInKg'+idval).val()||0;
            var uomfactor=$('#prepuomfactor'+idval).val()||0;
            var prdbrowid=$('#prdRowIdVal').val();
            var prdAmountKg=$('#prdQuantityKg').val()||0;
            var calcshortageacc=0;
            var calcoverageacc=0;
            var calctotaloverage=0;
            var conqty=0;
            var totalInsertedQuantity=0;

            quantitykg = quantitykg == '' ? 0 : quantitykg;
            prdAmountKg = prdAmountKg == '' ? 0 : prdAmountKg;

            quantity = quantity == '' ? 0 : quantity;
            uomfactor = uomfactor == '' ? 0 : uomfactor;
            conqty=parseFloat(quantity)*parseFloat(uomfactor);

            $.each($('#prepDynamicTable').find('.quantityKg'+prdbrowid), function() {
                if ($(this).val() != '' && !isNaN($(this).val())) {
                    totalInsertedQuantity+= parseFloat($(this).val());
                }
            });

            calcshortageacc= parseFloat(conqty) * (parseInt(1) - (parseFloat(shortageacc)/100));
            calcoverageacc= parseFloat(conqty) * (parseInt(1) + (parseFloat(overageacc)/100));

            calctotaloverage= parseFloat(prdAmountKg) * (parseInt(1) + (parseFloat(overageacc)/100));
            
            if(parseFloat(totalInsertedQuantity)>parseFloat(calctotaloverage)){
                toastrMessage('error',"Quantity should not be greater than the maximum defined overage accuracy","Error");
                $('#prepQuantityInKg'+idval).val("");
                $('#prepQuantityInKg'+idval).css("background",errorcolor);
                $('#varianceoverage'+idval).val("");
            }
            //else if(parseFloat(quantitykg)<parseFloat(calcshortageacc)){
            //   toastrMessage('error',"Quantity should not be less than the minimum defined shortage accuracy","Error");
            //    $('#prepQuantityInKg'+idval).val("");
            //    $('#prepQuantityInKg'+idval).css("background",errorcolor);
            //   $('#varianceshortage'+idval).val("");
            //}
            else if(parseFloat(quantitykg)>parseFloat(calcoverageacc)){
                toastrMessage('error',"Quantity should not be greater than the maximum defined overage accuracy","Error");
                $('#prepQuantityInKg'+idval).val("");
                $('#prepQuantityInKg'+idval).css("background",errorcolor);
                $('#varianceoverage'+idval).val("");
            }
            else if(parseFloat(quantitykg) >= parseFloat(calcshortageacc) && parseFloat(quantitykg) <= parseFloat(calcoverageacc) && parseFloat(totalInsertedQuantity) <= parseFloat(calctotaloverage)){
                $('#prepQuantityInKg'+idval).css("background","white");
            }
            CalculateCommTotal(prdbrowid);
        }

        function prepCommTypeFn(ele) {
            var prdid=$('#productionId').val();
            var idval = $(ele).closest('tr').find('.prepvals').val();
            var commtype=$('#prepCommType'+idval).val()||0;
            var origin=$('#prepOrigin'+idval).val()||0;
            var grade=$('#prepGrade'+idval).val()||0;
            var processtype=$('#prepProcessType'+idval).val();
            var cropyear=$('#prepCropYear'+idval).val()||0;
            var storeval=$('#prepstore'+idval).val()||0;
            var floormapval=$('#prepFloorMap'+idval).val()||0;
            var uom=$('#prepUom'+idval).val()||0;
            var defaultoption='<option selected value=""></option>';
            var commtypecnt=0;
            for(var k=1;k<=m;k++){
                if(($('#prepOrigin'+k).val())!=undefined){
                    if((parseInt($('#prepCommType'+k).val()) == parseInt(commtype)) && (parseInt($('#prepOrigin'+k).val()) == parseInt(origin)) && (parseInt($('#prepGrade'+k).val()) == parseInt(grade)) && ($('#prepProcessType'+k).val()==processtype) && (parseInt($('#prepCropYear'+k).val()) == parseInt(cropyear)) && (parseInt($('#prepstore'+k).val()) == parseInt(storeval)) && (parseInt($('#prepFloorMap'+k).val()) == parseInt(floormapval))){
                        commtypecnt+=1;
                    }
                }
            }

            if(parseInt(commtypecnt)<=1){
                $('#prepOrigin'+idval).empty();
                if(parseInt(commtype)==1 || parseInt(commtype)==2){
                    var originoptions = $("#regiondefault > option").clone();
                    $('#prepOrigin'+idval).append(originoptions);
                    $("#prepOrigin"+idval+" option[title!="+prdid+"]").remove(); 
                    $("#prepOrigin"+idval+" option[value=1]").remove();
                    $('#prepOrigin'+idval).append(defaultoption);
                    $('#prepOrigin'+idval).select2
                    ({
                        placeholder: "Select Region, Zone, Woreda here",
                        dropdownCssClass : 'cusprop',
                    });
                }
                else if(parseInt(commtype)==3){
                    var originoptions = $("#regiondefault > option").clone();
                    $('#prepOrigin'+idval).append(originoptions);
                    $("#prepOrigin"+idval+" option[title!="+prdid+"]").remove(); 
                    $("#prepOrigin"+idval+" option[value!=1]").remove(); 
                    $('#prepOrigin'+idval).append(defaultoption);
                    $('#prepOrigin'+idval).select2
                    ({
                        placeholder: "Select Region, Zone, Woreda here",
                        dropdownCssClass : 'cusprop',
                        minimumResultsForSearch: -1
                    });
                }
                $('#select2-prepCommType'+idval+'-container').parent().css({"position":"relative","z-index":"2","display":"grid","table-layout":"fixed","width":"100%","background-color":"white"});
                $('#select2-prepOrigin'+idval+'-container').parent().css({"position":"relative","z-index":"2","display":"grid","table-layout":"fixed","width":"100%","background-color":"white"});
            }
            else if(parseInt(commtypecnt)>1){
                $('#prepCommType'+idval).val(null).trigger('change').select2
                ({
                    placeholder: "Select here...",
                    minimumResultsForSearch: -1
