        function calcPrdQtyOnHand(rowid){
            var commtype="";
            var origin="";
            var grade="";
            var processtype="";
            var cropyear="";
            var storeval="";
            var floormap="";
            var uom="";
            var quantity=0;
            var quantityKg=0;
            var baseRecordId=0;
            var prdbrowid=$('#prdRowIdVal').val();
            var prdAmountKg=$('#prdQuantityKg').val();
            var prduomname=$('#prdUomNameVal').val();
            var prdquantity=$('#prdQuantityVal').val();
            var prduomfactor=$('#prdUomFactorVal').val();
            var supplierid="";
            var grnnumber="";
            var prdordernumber="";
            var certnumber="";
            var totalavailablebalance=0;
            var totalavailablebalancekg=0;
            var totalqnt=0;
            var totalkg=0;
            var convertedqty=0;
            var totalbagweight=0;
            var totalqtykg=0;
            var totalbalance=0;
            var totalbalancekg=0;
            $.ajax({
                url: '/calcPrepComBalance',
                type: 'POST',
                data:{
                    commtype:$('#prdCommodityTypeVal').val(),
                    origin:$('#prdRegionVal').val(),
                    grade:$('#prdGradeVal').val(),
                    processtype:$('#prdProcessTypeVal').val(),
                    cropyear:$('#predCropYearVal').val(),
                    storeval:$('#prdStoreVal').val(),
                    supplierid:$('#prdSupplierId').val(),
                    grnnumber:$('#prdGrnNumberInp').val(),
                    prdordernumber:$('#prdProductionNumber').val(),
                    certnumber:$('#prdCertificateNumber').val(),
                    floormap:$('#prepFloorMap'+rowid).val(),
                    uom:$('#prepUom'+rowid).val(),
                    baseRecordId:$('#productionId').val(),
                },
                beforeSend: function() {
                    cardSection.block({
                        message:
                        '<div class="d-flex justify-content-center align-items-center"><p class="mr-50 mb-50">Loading Please Wait...</p><div class="spinner-grow spinner-grow-sm text-white" role="status"></div> </div>',
                        css: {
                        backgroundColor: 'transparent',
                        color: '#fff',
                        border: '0'
                        },
                        overlayCSS: {
                        opacity: 0.5
                        }
                    });
                },
                complete: function () { 
                    cardSection.block({
                        message:
                            '',
                            timeout: 1,
                            css: {
                            backgroundColor: '',
                            color: '',
                            border: ''
                            }, 
                    });     
                },
                success: function(data) {
                    quantity=$('#prepQuantity'+rowid).val()||0;
                    quantityKg=$('#prepQuantityInKg'+rowid).val()||0;
                    $('#prepuomfactor'+rowid).val(data.uomfactor);
                    $('#prepuombagweight'+rowid).val(data.bagweight);
                    $('#prepQtyOnHand'+rowid).val("");
                    $('#prepQtyOnHandKG'+rowid).val("");

                    $('tr.prdregion'+prdbrowid).each(function(index) {
                        var row = $(this);
                        var currid=row.find('td').eq(1).find('input').val()||0;
                        if(parseInt(currid)<parseInt(rowid)){
                            var bagqnt=row.find('td').eq(7).find('input').val()||0;
                            var kgqnt=row.find('td').eq(8).find('input').val()||0;
                            var uomfactor=row.find('td').eq(11).find('input').val()||0;
                            totalqnt+= parseFloat(bagqnt);
                            totalkg+= parseFloat(kgqnt);
                        }
                    });

                    convertedqty=parseFloat(totalqnt)/parseFloat(data.uomfactor);
                   
                    totalavailablebalancekg=(parseFloat(data.avbalancekg)+parseFloat(totalqnt));
                    
                    totalavailablebalance=parseFloat(totalavailablebalancekg)/parseFloat(data.uomfactor).toFixed(2);
                    totalbalance=(parseFloat(data.avbalancebag)+parseFloat(data.stockoutbag))-parseFloat(totalqnt);
                    totalbalancekg=(parseFloat(data.avbalancekg)+parseFloat(data.stockoutkg))-parseFloat(totalkg);

                    if(parseFloat(totalbalance)<parseFloat(quantity)){
                        $('#prepQtyOnHand'+rowid).val("");
                        $('#prepQuantityInKg'+rowid).val(""); 
                        $('#prepQuantity'+rowid).val(""); 
                        $('#prepQtyOnHandKG'+rowid).val("");
                        $('#prepQuantity'+rowid).prop("readonly",true); 
                        $('#prepQuantityInKg'+rowid).prop("readonly",true); 
                        toastrMessage('error',"Insufficent quantity","Error");
                    }
                    else if(parseFloat(totalbalance)>=parseFloat(quantity)){
                        var conquantity=parseFloat(data.uomfactor)*parseFloat(quantity);
                        var avqtybykg=$('#prepQuantityInKg'+rowid).val()||0; 
                        $('#prepQtyOnHand'+rowid).val(totalbalance);
                        $('#prepQtyOnHandKG'+rowid).val(totalbalancekg);
                        $('#qtyonhandhid'+rowid).val(parseFloat(totalbalance)); 
                        $('#qtyonhandkghid'+rowid).val(parseFloat(totalbalancekg)); 
                        $('#prepQuantity'+rowid).attr('maxlength',totalbalance);
                        $('#prepQuantity'+rowid).prop("readonly",false); 
                        
                        $.each($('#prepDynamicTable').find('.preptotalbw'+prdbrowid), function() {
                            if ($(this).val() != '' && !isNaN($(this).val())) {
                                totalbagweight+= parseFloat($(this).val());
                            }
                        });
                        $('#BagWeight'+prdbrowid).val(totalbagweight.toFixed(2));
                        $('#bagweightlbl'+prdbrowid).html(totalbagweight.toFixed(2));
                    }
                    var qty=$('#prepQuantity'+rowid).val()||0;
                    $('#preptotalbagweight'+rowid).val(parseFloat(data.bagweight)* parseFloat(qty));
                    CalculateCommTotal(prdbrowid);
                    //CalcEachQtyOnHand(prdbrowid);
                }
            });
        }

