        function CalculateCommTotal(currId){
            var totalnumbag=0;
            var totalbagweight=0;
            var totalweight=0;
            var netweightval=0;
            var netweightres=0;
            var varshortage=0;
            var varoverage=0;

            var moistureval= $('#MoisturePercent'+currId).val()||0;
            var weightkg= $('#WeightKG'+currId).val()||0;
            var numofbag= $('#NoOfBag'+currId).val()||0;
            var bagweight= $('#BagWeight'+currId).val()||0;
            var adjustment= $('#Adjustment'+currId).val()||0;
            var netweight= $('#NetWeight'+currId).val()||0;

            $.each($('#prepDynamicTable').find('.quantityKg'+currId), function() {
                if ($(this).val() != '' && !isNaN($(this).val())) {
                    totalweight+= parseFloat($(this).val());
                }
            });

            $.each($('#prepDynamicTable').find('.quantityBag'+currId), function() {
                if ($(this).val() != '' && !isNaN($(this).val())) {
                    totalnumbag+= parseFloat($(this).val());
                }
            });

            $.each($('#prepDynamicTable').find('.preptotalbw'+currId), function() {
                if ($(this).val() != '' && !isNaN($(this).val())) {
                    totalbagweight+= parseFloat($(this).val());
                }
            });

            $.each($('#prepDynamicTable').find('.varshortage'+currId), function() {
                if ($(this).val() != '' && !isNaN($(this).val())) {
                    varshortage+= parseFloat($(this).val());
                }
            });

            $.each($('#prepDynamicTable').find('.varoverage'+currId), function() {
                if ($(this).val() != '' && !isNaN($(this).val())) {
                    varoverage+= parseFloat($(this).val());
                }
            });

            $('#WeightKG'+currId).val(totalweight.toFixed(2));
            $('#weightkglbl'+currId).html(totalweight.toFixed(2));

            $('#NoOfBag'+currId).val(totalnumbag.toFixed(2));
            $('#nofobaglbl'+currId).html(totalnumbag.toFixed(2));

            $('#totvarshortageinp'+currId).val(varshortage.toFixed(2));
            $('#totvarshortage'+currId).html(varshortage.toFixed(2));

            $('#totvaroverageinp'+currId).val(varoverage.toFixed(2));
            $('#totvaroverage'+currId).html(varoverage.toFixed(2));

            $('#BagWeight'+currId).val(totalbagweight.toFixed(2));
            $('#bagweightlbl'+currId).html(totalbagweight.toFixed(2));

            netweightval=parseFloat(totalbagweight)-parseFloat(adjustment);
            netweightres=parseFloat(totalweight)-parseFloat(netweightval);

            if(parseFloat(netweightres)>=0){
                $('#NetWeight'+currId).val(netweightres.toFixed(2));
                $('#netweightlbl'+currId).html(netweightres.toFixed(2));
            }

            if(parseFloat(netweightres)<0){
                $('#NetWeight'+currId).val("0.00");
                $('#netweightlbl'+currId).html("0.00");
            }

            if(parseFloat(adjustment) > parseFloat(totalbagweight)){
                $('#Adjustment'+currId).css("background",errorcolor);
                $('#Adjustment'+currId).val("");
                toastrMessage('error',"Adjustment can not be greater than Bag weight","Error");
            }
            CalculatePrdGrandTotal();
        }

        function CalculatePrdGrandTotal(){
            var bagtotal=0;
            var kgtotal=0;
            var bagweight=0;
            var totaladjustment=0;
            var totalnetweight=0;
            var totalvarshortage=0;
            var totalvaroverage=0;

            $.each($('#prepDynamicTable').find('.prepQuantity'), function() {
                if ($(this).val() != '' && !isNaN($(this).val())) {
                    bagtotal+= parseFloat($(this).val());
                }
            });

            $.each($('#prepDynamicTable').find('.prepQuantityInKg'), function() {
                if ($(this).val() != '' && !isNaN($(this).val())) {
                    kgtotal+= parseFloat($(this).val());
                }
            });

            $.each($('#prepDynamicTable').find('.preptotalbagweight'), function() {
                if ($(this).val() != '' && !isNaN($(this).val())) {
                    bagweight+= parseFloat($(this).val());
                }
            });

            $.each($('.commoditytotaltbl').find('.Adjustment'), function() {
                if ($(this).val() != '' && !isNaN($(this).val())) {
                    totaladjustment+= parseFloat($(this).val());
                }
            });

            $.each($('.commoditytotaltbl').find('.NetWeight'), function() {
                if ($(this).val() != '' && !isNaN($(this).val())) {
                    totalnetweight+= parseFloat($(this).val());
                }
            });

            $.each($('#prepDynamicTable').find('.varianceshortage'), function() {
                if ($(this).val() != '' && !isNaN($(this).val())) {
                    totalvarshortage+= parseFloat($(this).val());
                }
            });

            $.each($('#prepDynamicTable').find('.varianceoverage'), function() {
                if ($(this).val() != '' && !isNaN($(this).val())) {
                    totalvaroverage+= parseFloat($(this).val());
                }
            });


            $("#WeightinKGVal").val(kgtotal.toFixed(2));
            $("#WeightinKGLbl").html(kgtotal.toFixed(2));

            $("#NoOfBagVal").val(bagtotal.toFixed(2));
            $("#NoOfBagLbl").html(bagtotal.toFixed(2));

            $("#gTotalVarianceShortage").val(totalvarshortage.toFixed(2));
            $("#grandTotalVarShortage").html(totalvarshortage.toFixed(2));

            $("#gTotalVarianceOverage").val(totalvaroverage.toFixed(2));
            $("#grandTotalVarOverage").html(totalvaroverage.toFixed(2));

            $("#BagWeightVal").val(bagweight.toFixed(2));
            $("#BagWeightLbl").html(bagweight.toFixed(2));

            $("#AdjustmentVal").val(totaladjustment.toFixed(2));
            $("#AdjustmentLbl").html(totaladjustment.toFixed(2));

            $("#NetWeightVal").val(totalnetweight.toFixed(2));
            $("#NetWeightLbl").html(totalnetweight.toFixed(2));
        }

        function adjustmentFn(currId){
            var netweightval=0;
            var netweightres=0;
            var moistureval= $('#MoisturePercent'+currId).val()||0;
            var weightkg= $('#WeightKG'+currId).val()||0;
            var numofbag= $('#NoOfBag'+currId).val()||0;
            var bagweight= $('#BagWeight'+currId).val()||0;
            var adjustment= $('#Adjustment'+currId).val()||0;
            var netweight= $('#NetWeight'+currId).val()||0;

            netweightval=parseFloat(bagweight)-parseFloat(adjustment);
            netweightres=parseFloat(weightkg)-parseFloat(netweightval);
            if(parseFloat(netweightres)>=0 && parseFloat(bagweight) > parseFloat(adjustment)){
                $('#NetWeight'+currId).val(netweightres.toFixed(2));
                $('#netweightlbl'+currId).html(netweightres.toFixed(2));
                $('#Adjustment'+currId).css("background","white");
                CalculatePrdGrandTotal();
            }
            else if(parseFloat(adjustment) > parseFloat(bagweight)){
                $('#Adjustment'+currId).css("background",errorcolor);
                $('#Adjustment'+currId).val("");
                toastrMessage('error',"Adjustment can not be greater than Bag weight","Error");
            }
        }

        function moistureTblFn(currId){
            var totalmoisture=0;
            var moistureval=$("#MoisturePercent"+currId).val()||0;
            var maxMoisturePercent=15;
            if(parseFloat(moistureval)<=parseFloat(maxMoisturePercent)){

                $.each($('.commoditytotaltbl').find('.MoisturePercent'), function() {
                    if ($(this).val() != '' && !isNaN($(this).val())) {
                        totalmoisture+= parseFloat($(this).val());
                    }
                });

                $("#MoisturePercentTotal").val(totalmoisture.toFixed(2));
                $("#MoisturePercentTotalLbl").html(totalmoisture.toFixed(2));
                $('#MoisturePercent'+currId).css("background","white");
            }
            else if(parseFloat(moistureval)>parseFloat(maxMoisturePercent)){
                $('#MoisturePercent'+currId).css("background",errorcolor);
                $('#MoisturePercent'+currId).val("");
                toastrMessage('error',"Moisture percent can not be greater than "+maxMoisturePercent+" %","Error");
            }
        }

