        $("#startresumebtn").click(function() {
            var optype = $("#prdStatusVal").val();
            var registerForm = $("#ProductionForm");
            var formData = registerForm.serialize();
            var depmame="";
            var lastdep="";
            $.ajax({ 
                url: '/saveProduction',
                type: 'POST',
                data: formData,
                beforeSend: function() {
                    cardSection.block({
                        message:
                        '<div class="d-flex justify-content-center align-items-center"><p class="mr-50 mb-50">Loading Please Wait...</p><div class="spinner-grow spinner-grow-sm text-white" role="status"></div> </div>',
                        css: {
                        backgroundColor: 'transparent',
                        color: '#fff',
                        border: '0'
                        },
                        overlayCSS: {
                        opacity: 0.5
                        }
                    });
                    if(parseFloat(optype)==1){
                        $('#startresumebtn').text('Starting...');
                        $('#startresumebtn').prop("disabled", true);
                    }
                    else if(parseFloat(optype)==2){
                        $('#startresumebtn').text('Updating...');
                        $('#startresumebtn').prop("disabled", true);
                    }
                },
                complete: function () { 
                    cardSection.block({
                        message:
                            '',
                            timeout: 1,
                            css: {
                            backgroundColor: '',
                            color: '',
                            border: ''
                            }, 
                    });     
                },
                statusCode: {
                    401: function() {
                        toastrMessage('error',"Session Expired!","Error");
                        location.reload(false);
                    },
                    503: function(){
                        if(parseFloat(optype)==1){
                            $('#startresumebtn').text('Starting...');
                            $('#startresumebtn').prop("disabled", true);
                        }
                        else if(parseFloat(optype)==2){
                            $('#startresumebtn').text('Updating...');
                            $('#startresumebtn').prop("disabled", true);
                        }
                        toastrMessage('error',"Authentication Failed","Error");
                    }
                },
                success: function(data) {
                    if (data.errors) {
                        if (data.errors.ProductionStore) {
                            $('#productionstore-error').html(data.errors.ProductionStore[0]);
                        }

                        if(parseFloat(optype)==1){
                            $('#startresumebtn').text('Start');
                            $('#startresumebtn').prop("disabled", false);
                        }
                        else if(parseFloat(optype)==2){
                            $('#startresumebtn').text('Update');
                            $('#startresumebtn').prop("disabled", false);
                        }
                        toastrMessage('error',"Please check your input","Error");
                    }
                    else if (data.errorv2) {
                        var othermessage="";
                        var zeromessage="";
                        for(var k=1;k<=mm;k++){
                            var rowidnumber=$('#rownumid'+k).text();
                            var prepdate=$('#prepDate'+k).val();
                            var prepfloormap=$('#prepFloorMap'+k).val();
                            var prepuom=$('#prepUom'+k).val();
                            var prepqtyonhand=$('#prepQtyOnHand'+k).val();
                            var prepquantity=$('#prepQuantity'+k).val();
                            var prepquantityinkg=$('#prepQuantityInKg'+k).val();

                            if(($('#prepDate'+k).val())!=undefined){
                                if(prepdate==""||prepdate==null){
                                    $('#prepDate'+k).css("background", errorcolor);
                                }
                            }
                            if(($('#prepFloorMap'+k).val())!=undefined){
                                if(prepfloormap==""||prepfloormap==null){
                                    $('#select2-prepFloorMap'+k+'-container').parent().css({"position":"relative","z-index":"2","display":"grid","table-layout":"fixed","width":"100%","background-color":errorcolor});
                                }
                            }
                            if(($('#prepUom'+k).val())!=undefined){
                                if(prepuom==""||prepuom==null){
                                    $('#select2-prepUom'+k+'-container').parent().css({"position":"relative","z-index":"2","display":"grid","table-layout":"fixed","width":"100%","background-color":errorcolor});
                                }
                            }
                            if(($('#prepQuantity'+k).val())!=undefined){
                                if(prepquantity==""||prepquantity==null){
                                    $('#prepQuantity'+k).css("background", errorcolor);
                                }
                                if(parseFloat(prepqtyonhand)<parseFloat(prepquantity)){
                                    $('#prepQuantity'+k).css("background", errorcolor);
                                    othermessage+="</br> Quantity by UOM is greater than Quanity on Hand on <b><i>Row "+rowidnumber+"</i></b></br>_______________";
                                }
                                if(parseFloat(prepquantity)==0){
                                    $('#prepQuantity'+k).css("background", errorcolor);
                                    zeromessage+="</br> Quantity by UOM should be greater than zero(0) on <b><i>Row "+rowidnumber+"</i></b></br>_______________";
                                }
                            }
                            if(($('#prepQuantityInKg'+k).val())!=undefined){
                                if(prepquantityinkg==""||prepquantityinkg==null){
                                    $('#prepQuantityInKg'+k).css("background", errorcolor);
                                }
                            }
                        }

                        if(parseFloat(optype)==1){
                            $('#startresumebtn').text('Start');
                            $('#startresumebtn').prop("disabled", false);
                        }
                        else if(parseFloat(optype)==2){
                            $('#startresumebtn').text('Update');
                            $('#startresumebtn').prop("disabled", false);
                        }
                        toastrMessage('error',"Please insert valid data on highlighted fields</br>"+othermessage+zeromessage,"Error");
                    }
                    else if (data.emptyrow) {
                        if(parseFloat(optype)==1){
                            $('#startresumebtn').text('Start');
                            $('#startresumebtn').prop("disabled", false);
                        }
                        else if(parseFloat(optype)==2){
                            $('#startresumebtn').text('Update');
                            $('#startresumebtn').prop("disabled", false);
                        }
                        $('#prepdynamictbl-error').html("Add record here");
                        toastrMessage('error',"You should add atleast one record","Error");
                    }
                    else if (data.dberrors) {
                        if(parseFloat(optype)==1){
                            $('#startresumebtn').text('Start');
                            $('#startresumebtn').prop("disabled", false);
                        }
                        else if(parseFloat(optype)==2){
                            $('#startresumebtn').text('Update');
                            $('#startresumebtn').prop("disabled", false);
                        }
                        toastrMessage('error',"Please contact administrator","Error");
                    }
                    else if(data.success){
                        if(parseFloat(optype)==1){
                            $('#startresumebtn').text('Start');
                            $('#startresumebtn').prop("disabled", false);
                        }
                        else if(parseFloat(optype)==2){
                            $('#startresumebtn').text('Update');
                            $('#startresumebtn').prop("disabled", false);
                        }
                        toastrMessage('success',"Successful","Success");
                        var oTable = $('#laravel-datatable-crud').dataTable();
                        oTable.fnDraw(false);
                        $("#productionmodal").modal('hide');
                        $("#informationmodal").modal('hide');
                    }
                }
            });
        });

