                        $('#completepdprcbtn').text('Finish Process');
                        $('#completepdprcbtn').prop("disabled",false);
                        $('#completeprdprocessmodal').modal('hide');
                        toastrMessage('error',"The duration has not been fully recorded. Please pause the timer","Error");
                    }
                    else if(data.durationemptyerror){
                        $('#completepdprcbtn').text('Finish Process');
                        $('#completepdprcbtn').prop("disabled",false);
                        $('#completeprdprocessmodal').modal('hide');
                        toastrMessage('error',"Duration log not found","Error");
