            var ceroption = '';
            var defaultoption = '<option selected value=""></option>';
            var expcertnumber = $("#certificateNoDefault > option").clone();

            var coffeetypecnt=0;
            for(var k=1;k<=mmm;k++){
                if(($('#expcoffeetype'+k).val())!=undefined){
                    if((parseInt($('#expfloormap'+k).val()) == parseInt(floormapvar)) && (parseInt($('#expcoffeetype'+k).val()) == parseInt(expcoffeetype)) && (parseInt($('#expcertnum'+k).val()) == parseInt(expcernum)) && (parseInt($('#exprefuom'+k).val()) == parseInt(exprefuom)) && parseInt(exprefuom)>0){
                        coffeetypecnt+=1;
                    }
                }
            }

            if(parseInt(coffeetypecnt)<=1){
                if(parseInt(expcoffeetype)==4 || parseInt(expcoffeetype)==5 || parseInt(expcoffeetype)==6){
                    ceroption = '<option title="'+prdId+'" value="0">-</option>';
                }
                $('#expcertnum'+idval).empty();
                $('#expcertnum'+idval).append(ceroption);
                $('#expcertnum'+idval).append(expcertnumber);
                $("#expcertnum"+idval+" option[title!="+prdId+"]").remove(); 
                $('#expcertnum'+idval).append(defaultoption);
                
                $('#expcertnum'+idval).select2
                ({
                    placeholder: "Select Certificate No. here",
                    dropdownCssClass : 'cusprop',
                });
                $('#select2-expcertnum'+idval+'-container').parent().css({"position":"relative","z-index":"2","display":"grid","table-layout":"fixed","width":"100%","background-color":"white"});
                $('#select2-expcoffeetype'+idval+'-container').parent().css({"position":"relative","z-index":"2","display":"grid","table-layout":"fixed","width":"100%","background-color":"white"});
            }
            else if(parseInt(coffeetypecnt)>1){
                $('#expcoffeetype'+idval).val(null).trigger('change').select2
                ({
                    placeholder: "Select Coffee type here",
                    dropdownCssClass : 'cusprop',
