        function CalculateTotalExep(param){
            var refnumbag=0;
            var refweightkg=0;
            var netkginpval=0;
            var blanknumbag=0;
            var blankweightkg=0;
            var bagweight=0;
            var netkg=0;
            var feresula=0;
            var variance=0;

            var totalnumofbag=0;
            var totalweightkg=0;

            var refuomfactor=0;
            var refuomweightkg=0;

            var blankuomfactor=0;
            var blankuomweightkg=0;

            var reftotweightkg=0;
            var blanktotweightkg=0;

            var totalrefnumofbag=0;
            var totalrefweightkg=0;
            var totalblanknumofbag=0;
            var totalblankweightkg=0;
            var totaloftotnumofbag=0;
            var totaloftotweightkg=0;
            var totalbagweight=0;
            var totalnetkg=0;
            var totalferesula=0;
            var totalshortage=0;
            var totaloverage=0;

            var indnum=0;

            $('#expDynamicTable > tbody > tr').each(function() {
                indnum = $(this).find('td').eq(1).find('input').val();

                refuomfactor = $('#expuomreffactor'+indnum).val();
                refuomweightkg = $('#expuomrefbagweight'+indnum).val();
                blankuomfactor = $('#expuomtotalfactor'+indnum).val();
                blankuomweightkg = $('#expuomtotalbagweight'+indnum).val();
                //totalkg = $('#exprefkg'+indnum).val();

                refnumbag = $('#exprefbagnum'+indnum).val();
                blanknumbag = $('#expblankbagnum'+indnum).val();

                refnumbag = refnumbag == '' ? 0 : refnumbag;
                refuomweightkg = refuomweightkg == '' ? 0 : refuomweightkg;

                reftotweightkg=parseFloat(refnumbag)*parseFloat(refuomfactor);
                blanktotweightkg=parseFloat(blanknumbag)*parseFloat(blankuomfactor);
                bagweight=parseFloat(refuomweightkg)*parseFloat(refnumbag);
                $('#bagweight'+indnum).val(bagweight.toFixed(2));

                if(parseInt(param)==1){
                    
                    refweightkg=$('#exptotalkg'+indnum).val();
                    blankweightkg=$('#expblankkg'+indnum).val();
                    
                    refweightkg = refweightkg == '' ? 0 : refweightkg;
                    blanknumbag = blanknumbag == '' ? 0 : blanknumbag;
                    blankweightkg = blankweightkg == '' ? 0 : blankweightkg;
                    bagweight = bagweight == '' ? 0 : bagweight;

                    totalnumofbag=parseFloat(refnumbag)+parseFloat(blanknumbag);
                    totalweightkg=parseFloat(refweightkg)+parseFloat(blankweightkg);
                    netkg=parseFloat(refweightkg)-parseFloat(bagweight);
                    feresula=parseFloat(netkg)/17;  
                    $('#expnetkg'+indnum).val(parseFloat(netkg) <= 0 ? '' : netkg.toFixed(2));
                }
                else if(parseInt(param)==2){
                    netkg=$('#expnetkg'+indnum).val();

                    netkg = netkg == '' ? 0 : netkg;
                    blanknumbag = blanknumbag == '' ? 0 : blanknumbag;
                    blankweightkg = blankweightkg == '' ? 0 : blankweightkg;
                    bagweight = bagweight == '' ? 0 : bagweight;

                    totalnumofbag=parseFloat(refnumbag)+parseFloat(blanknumbag);
                    totalweightkg=parseFloat(refweightkg)+parseFloat(blankweightkg);
                    refweightkg=parseFloat(netkg)+parseFloat(bagweight);
                    feresula=parseFloat(netkg)/17;  
                    $('#exptotalkg'+indnum).val(parseFloat(refweightkg) <= 0 ? '' :parseFloat(refweightkg).toFixed(2));
                }
                else{
                    $('#bagweight'+indnum).val(bagweight.toFixed(2));

                    refweightkg=$('#exptotalkg'+indnum).val();
                    blankweightkg=$('#expblankkg'+indnum).val();
                    
                    refweightkg = refweightkg == '' ? 0 : refweightkg;
                    blanknumbag = blanknumbag == '' ? 0 : blanknumbag;
                    blankweightkg = blankweightkg == '' ? 0 : blankweightkg;
                    bagweight = bagweight == '' ? 0 : bagweight;

                    totalnumofbag=parseFloat(refnumbag)+parseFloat(blanknumbag);
                    totalweightkg=parseFloat(refweightkg)+parseFloat(blankweightkg);
                    netkg=parseFloat(refweightkg)-parseFloat(bagweight);
                    feresula=parseFloat(netkg)/17;  
                    $('#expnetkg'+indnum).val(parseFloat(netkg) <= 0 ? '' : netkg.toFixed(2));
                }
                
                $('#expferesula'+indnum).val(parseFloat(feresula) <= 0 ? '' : feresula.toFixed(2));
                $('#expshortage'+indnum).val("");
                $('#expoverage'+indnum).val("");
                
                if(parseFloat(netkg) > parseFloat(reftotweightkg) && parseFloat(netkg)>0 && parseFloat(refweightkg)>0 && parseFloat(bagweight)>0){
                    variance=parseFloat(netkg)-parseFloat(reftotweightkg);
                    $('#expoverage'+indnum).val(parseFloat(variance) <= 0 ? '' : variance.toFixed(2));
                }
                else if(parseFloat(reftotweightkg) > parseFloat(netkg) && parseFloat(netkg)>0 && parseFloat(refweightkg)>0 && parseFloat(bagweight)>0){
                    variance=parseFloat(reftotweightkg)-parseFloat(netkg);
                    $('#expshortage'+indnum).val(parseFloat(variance) <= 0 ? '' : variance.toFixed(2));
                }
            });

            

            $.each($('#expDynamicTable').find('.exprefbagnum'), function() {
                if ($(this).val() != '' && !isNaN($(this).val())) {
                    totalrefnumofbag += parseFloat($(this).val());
                }
            });

            $.each($('#expDynamicTable').find('.exprefkg'), function() {
                if ($(this).val() != '' && !isNaN($(this).val())) {
                    totalrefweightkg += parseFloat($(this).val());
                }
            });

            $.each($('#expDynamicTable').find('.exptotalbagnum'), function() {
                if ($(this).val() != '' && !isNaN($(this).val())) {
                    totaloftotnumofbag += parseFloat($(this).val());
                }
            });

            $.each($('#expDynamicTable').find('.exptotalkg'), function() {
                if ($(this).val() != '' && !isNaN($(this).val())) {
                    totaloftotweightkg += parseFloat($(this).val());
                }
            });

            $.each($('#expDynamicTable').find('.expbagweight'), function() {
                if ($(this).val() != '' && !isNaN($(this).val())) {
                    totalbagweight += parseFloat($(this).val());
                }
            });

            $.each($('#expDynamicTable').find('.expnetkg'), function() {
                if ($(this).val() != '' && !isNaN($(this).val())) {
                    totalnetkg += parseFloat($(this).val());
                }
            });

            $.each($('#expDynamicTable').find('.expferesula'), function() {
                if ($(this).val() != '' && !isNaN($(this).val())) {
                    totalferesula += parseFloat($(this).val());
                }
            });

            $.each($('#expDynamicTable').find('.expshortage'), function() {
                if ($(this).val() != '' && !isNaN($(this).val())) {
                    totalshortage += parseFloat($(this).val());
                }
            });

            $.each($('#expDynamicTable').find('.expoverage'), function() {
                if ($(this).val() != '' && !isNaN($(this).val())) {
                    totaloverage += parseFloat($(this).val());
                }
            });

            $('#totalrefnumbag').html(parseInt(totalrefnumofbag) <= 0 ? '' : numformat(totalrefnumofbag));
            $('#totalbagweightkg').html(parseFloat(totalbagweight) <= 0 ? '' : numformat(totalbagweight.toFixed(2)));
            $('#totalofweightkg').html(parseFloat(totaloftotweightkg) <= 0 ? '' : numformat(totaloftotweightkg.toFixed(2)));
            //$('#totalrefweightkg').val(parseInt(totalrefweightkg) <= 0 ? '' : numformat(totalrefweightkg.toFixed(2)));
            $('#totalnetkg').html(parseFloat(totalnetkg) <= 0 ? '' : numformat(totalnetkg.toFixed(2)));
            $('#totalferesula').html(parseFloat(totalferesula) <= 0 ? '' : numformat(totalferesula.toFixed(2)));
            $('#totalshortages').html(parseFloat(totalshortage) <= 0 ? '' : numformat(totalshortage.toFixed(2)));
            $('#totaloverages').html(parseFloat(totaloverage) <= 0 ? '' : numformat(totaloverage.toFixed(2)));
            
            // $('#totalrefnumbag').html(numformat(totalrefnumofbag.toFixed(2)));
            // $('#totalbagweightkg').html(numformat(totalbagweight.toFixed(2)));
            // $('#totalrefweightkg').html(numformat(totalrefweightkg.toFixed(2)));
            
            // $('#totalofnumofbag').html(numformat(totaloftotnumofbag.toFixed(2)));
            // $('#totalofweightkg').html(numformat(totaloftotweightkg.toFixed(2)));
            CalculateSummary();
        }

