        function CalculateTotalRej(param){
            var refnumbag=0;
            var refweightkg=0;
            var blanknumbag=0;
            var blankweightkg=0;
            var bagweight=0;
            var netkg=0;
            var feresula=0;
            var variance=0;

            var totalnumofbag=0;
            var totalweightkg=0;

            var refuomfactor=0;
            var refuomweightkg=0;

            var blankuomfactor=0;
            var blankuomweightkg=0;

            var reftotweightkg=0;
            var blanktotweightkg=0;

            var totalrefnumofbag=0;
            var totalrefweightkg=0;
            var totalbagweight=0;
            var totalgrosskg=0;
            var totalblanknumofbag=0;
            var totalnetkg=0;
            var totalferesulakg=0;
            var totalrejshortagekg=0;
            var totalrejoveragekg=0;

            var indnum=0;

            $('#rejDynamicTable > tbody > tr').each(function() {
                indnum = $(this).find('td').eq(1).find('input').val();

                refuomfactor = $('#rejuomreffactor'+indnum).val();
                refuomweightkg = $('#rejuomrefbagweight'+indnum).val();
                blankuomfactor = $('#rejuomtotalfactor'+indnum).val();
                blankuomweightkg = $('#rejuomtotalbagweight'+indnum).val();

                refnumbag = $('#rejrefbagnum'+indnum).val();
                blanknumbag = $('#rejblankbagnum'+indnum).val();
                reftotweightkg=parseFloat(refnumbag)*parseFloat(refuomfactor);
                blanktotweightkg=parseFloat(blanknumbag)*parseFloat(blankuomfactor);
                bagweight=parseFloat(refuomweightkg)*parseFloat(refnumbag);
                $('#rejbagweight'+indnum).val(bagweight.toFixed(2));
                
                if(parseInt(param)==2){
                    netkg=$('#rejnetkg'+indnum).val();

                    netkg = netkg == '' ? 0 : netkg;
                    blanknumbag = blanknumbag == '' ? 0 : blanknumbag;
                    blankweightkg = blankweightkg == '' ? 0 : blankweightkg;
                    bagweight = bagweight == '' ? 0 : bagweight;

                    totalnumofbag=parseFloat(refnumbag)+parseFloat(blanknumbag);
                    //totalweightkg=parseFloat(refweightkg)+parseFloat(blankweightkg);
                    refweightkg=parseFloat(netkg)+parseFloat(bagweight);
                    feresula=parseFloat(netkg)/17;  
                    $('#rejtotalkg'+indnum).val(parseFloat(refweightkg) <= 0 ? '' :parseFloat(refweightkg).toFixed(2));
                }
                else{
                    
                    refweightkg=$('#rejtotalkg'+indnum).val();
                    blankweightkg=$('#rejblankkg'+indnum).val();
                    
                    refnumbag = refnumbag == '' ? 0 : refnumbag;
                    refweightkg = refweightkg == '' ? 0 : refweightkg;
                    blanknumbag = blanknumbag == '' ? 0 : blanknumbag;
                    blankweightkg = blankweightkg == '' ? 0 : blankweightkg;

                    totalnumofbag=parseFloat(refnumbag)+parseFloat(blanknumbag);
                    totalweightkg=parseFloat(refweightkg)+parseFloat(blankweightkg);
                    netkg=parseFloat(refweightkg)-parseFloat(bagweight);
                    feresula=parseFloat(netkg)/17;  

                    $('#rejnetkg'+indnum).val(parseInt(netkg) <= 0 ? '' : netkg.toFixed(2));
                }

                $('#rejferesula'+indnum).val(parseInt(feresula) <= 0 ? '' : feresula.toFixed(2));
                $('#rejshortage'+indnum).val("");
                $('#rejoverage'+indnum).val("");

                if(parseFloat(netkg) > parseFloat(reftotweightkg) && parseFloat(netkg)>0 && parseFloat(refweightkg)>0 && parseFloat(bagweight)>0){
                    variance=parseFloat(netkg)-parseFloat(reftotweightkg);
                    $('#rejoverage'+indnum).val(parseInt(variance) <= 0 ? '' : variance.toFixed(2));
                }
                else if(parseFloat(reftotweightkg) > parseFloat(netkg) && parseFloat(netkg)>0 && parseFloat(refweightkg)>0 && parseFloat(bagweight)>0){
                    variance=parseFloat(reftotweightkg)-parseFloat(netkg);
                    $('#rejshortage'+indnum).val(parseInt(variance) <= 0 ? '' : variance.toFixed(2));
                }
            });

            $.each($('#rejDynamicTable').find('.rejrefbagnum'), function() {
                if ($(this).val() != '' && !isNaN($(this).val())) {
                    totalrefnumofbag += parseFloat($(this).val());
                }
            });

            $.each($('#rejDynamicTable').find('.rejbagweight'), function() {
                if ($(this).val() != '' && !isNaN($(this).val())) {
                    totalbagweight += parseFloat($(this).val());
                }
            });

            $.each($('#rejDynamicTable').find('.rejtotalkg'), function() {
                if ($(this).val() != '' && !isNaN($(this).val())) {
                    totalgrosskg += parseFloat($(this).val());
                }
            });

            $.each($('#rejDynamicTable').find('.rejnetkg'), function() {
                if ($(this).val() != '' && !isNaN($(this).val())) {
                    totalnetkg += parseFloat($(this).val());
                }
            });

            $.each($('#rejDynamicTable').find('.rejferesula'), function() {
                if ($(this).val() != '' && !isNaN($(this).val())) {
                    totalferesulakg += parseFloat($(this).val());
                }
            });

            $.each($('#rejDynamicTable').find('.rejshortage'), function() {
                if ($(this).val() != '' && !isNaN($(this).val())) {
                    totalrejshortagekg += parseFloat($(this).val());
                }
            });

            $.each($('#rejDynamicTable').find('.rejoverage'), function() {
                if ($(this).val() != '' && !isNaN($(this).val())) {
                    totalrejoveragekg += parseFloat($(this).val());
                }
            });
            
            $('#rejtotalofnumofbag').html(parseInt(totalrefnumofbag) <= 0 ? '' : numformat(totalrefnumofbag.toFixed(2)));
            $('#rejtotalbagweight').html(parseInt(totalbagweight) <= 0 ? '' : numformat(totalbagweight.toFixed(2)));
            $('#rejtotalgrosskg').html(parseInt(totalgrosskg) <= 0 ? '' : numformat(totalgrosskg.toFixed(2)));
            $('#rejtotalnetkg').html(parseInt(totalnetkg) <= 0 ? '' : numformat(totalnetkg.toFixed(2)));
            $('#rejtotalferesula').html(parseInt(totalferesulakg) <= 0 ? '' : numformat(totalferesulakg.toFixed(2)));
            $('#rejtotalvarshortage').html(parseInt(totalrejshortagekg) <= 0 ? '' : numformat(totalrejshortagekg.toFixed(2)));
            $('#rejtotalvaroverage').html(parseInt(totalrejoveragekg) <= 0 ? '' : numformat(totalrejoveragekg.toFixed(2)));
           
            CalculateSummary();
        }

