        function CalculateTotalWes(param){
            var refnumbag=0;
            var refweightkg=0;
            var blanknumbag=0;
            var blankweightkg=0;
            var bagweight=0;
            var netkg=0;
            var feresula=0;
            var variance=0;

            var totalnumofbag=0;
            var totalweightkg=0;

            var refuomfactor=0;
            var refuomweightkg=0;

            var blankuomfactor=0;
            var blankuomweightkg=0;

            var reftotweightkg=0;
            var blanktotweightkg=0;

            var totalrefnumofbag=0;
            var totalbagweight=0;
            var totalnetkg=0;
            var totalferesula=0;
            var totalvarshortage=0;
            var totalvaroverage=0;

            var totalrefweightkg=0;
            var totalblanknumofbag=0;
            var totalblankweightkg=0;
            var totaloftotnumofbag=0;
            var totaloftotweightkg=0;

            var indnum=0;
            var wastype=0;

            $('#wesDynamicTable > tbody > tr').each(function() {
                indnum = $(this).find('td').eq(1).find('input').val();
                wastype = $(this).find('.wescoffeetype').val();

                refuomfactor = $('#wesuomreffactor'+indnum).val();
                refuomweightkg = $('#wesuomrefbagweight'+indnum).val();
                blankuomfactor = $('#wesuomtotalfactor'+indnum).val();
                blankuomweightkg = $('#wesuomtotalbagweight'+indnum).val();

                refnumbag = $('#wesrefbagnum'+indnum).val();
                blanknumbag = $('#wesblankbagnum'+indnum).val();

