        function CalculatePercentage(totalinp,prdnetkg){
            var percentage=100;
            var result=((parseFloat(prdnetkg)*parseFloat(percentage)) / parseFloat(totalinp));
            result = result <= 0 ? '' : parseFloat(result).toFixed(2);
            
            return result;
        }

