            $('#infosumstubbletotalcost').html(stbtotalcost <= 0 ? '' : numformat(parseFloat(stbtotalcost).toFixed(2)));

            $('#infosumtotalcost').html(grandtotalcost <= 0 ? '' : numformat(parseFloat(grandtotalcost).toFixed(2)));

            $('#infosumtotalnumofbag').html(totalofbag <= 0 ? '' : numformat(parseFloat(totalofbag).toFixed(2)));
            $('#infosumtotalweightbykg').html(totalofweight <= 0 ? '' : numformat(parseFloat(totalofweight).toFixed(2)));

            $('#infosumtotalprdnumofbag').html(prdtotalnumofkg <= 0 ? '' : numformat(parseFloat(prdtotalnumofkg)));
            $('#infosumtotalprdweightbykg').html(prdweightbykg <= 0 ? '' : numformat(parseFloat(prdweightbykg)));

            $('#infosumexppercentage').html(exportpercentage <= 0 ? '' : numformat(parseFloat(exportpercentage).toFixed(2)));
            $('#infosumexpprepercentage').html(expprepercentage <= 0 ? '' : numformat(parseFloat(expprepercentage).toFixed(2)));
            $('#infosumexpexcpercentage').html(expecxpercentage <= 0 ? '' : numformat(parseFloat(expecxpercentage).toFixed(2)));
            $('#infosumexpcanpercentage').html(expcanpercentage <= 0 ? '' : numformat(parseFloat(expcanpercentage).toFixed(2)));
            $('#infosumexprejpercentage').html(rejpercentage <= 0 ? '' : numformat(parseFloat(rejpercentage).toFixed(2)));
            $('#infosumexpstbpercentage').html(stbpercentage <= 0 ? '' : numformat(parseFloat(stbpercentage).toFixed(2)));
            $('#infosumexpwaspercentage').html(wespercentage <= 0 ? '' : numformat(parseFloat(wespercentage).toFixed(2)));

            exportpercentage = exportpercentage == '' ? 0 : exportpercentage;
            expprepercentage = expprepercentage == '' ? 0 : expprepercentage;
            expecxpercentage = expecxpercentage == '' ? 0 : expecxpercentage;
            expcanpercentage = expcanpercentage == '' ? 0 : expcanpercentage;
            rejpercentage = rejpercentage == '' ? 0 : rejpercentage;
            stbpercentage = stbpercentage == '' ? 0 : stbpercentage;
            wespercentage = wespercentage == '' ? 0 : wespercentage;

            totalpercentage=parseFloat(exportpercentage)+parseFloat(expprepercentage)+parseFloat(expecxpercentage)+parseFloat(expcanpercentage)+parseFloat(rejpercentage)+parseFloat(stbpercentage)+parseFloat(wespercentage);
            $('#sumtotalpercentage').html(totalpercentage <= 0 ? '' : numformat(parseFloat(totalpercentage).toFixed(1)));
            $('#infosumtotalpercentage').html(totalpercentage <= 0 ? '' : numformat(parseFloat(totalpercentage).toFixed(1)));

            variance=parseFloat(prdweightbykg||0)-parseFloat(totalofweight||0);
            if(parseFloat(variance)<0){
                variance=variance*(-1);
                $('#sumtotalvarweightbykg').html(variance <= 0 ? '' : numformat(parseFloat(variance).toFixed(2)));
                $("#variancelbl").html("Variance Overage");	
                $('#infosumtotalvarweightbykg').html(variance <= 0 ? '' : numformat(parseFloat(variance).toFixed(2)));
                $("#infovariancelbl").html("Variance Overage");	
            }
            else if(parseFloat(variance)>0){
                $('#sumtotalvarweightbykg').html(variance <= 0 ? '' : numformat(parseFloat(variance).toFixed(2)));
                $("#variancelbl").html("Variance Shortage");	
                $('#infosumtotalvarweightbykg').html(variance <= 0 ? '' : numformat(parseFloat(variance).toFixed(2)));
                $("#infovariancelbl").html("Variance Shortage");	
            }
            else if(parseFloat(variance)==0){
                $('#sumtotalvarweightbykg').html(variance <= 0 ? '' : numformat(parseFloat(variance).toFixed(2)));
                $("#variancelbl").html("Variance");	
                $('#infosumtotalvarweightbykg').html(variance <= 0 ? '' : numformat(parseFloat(variance).toFixed(2)));
                $("#infovariancelbl").html("Variance");	
            }
        }

        function outputTabFn(btnInd){
            $(".outputbtn").hide();
            if(parseInt(btnInd)==1){
                $('#saveexportbtn').text("Submit");
                $('#saveexportbtn').prop("disabled", false);
                $("#saveexportbtn").show();
            }
            else if(parseInt(btnInd)==2){
                $('#saverejectbtn').text("Submit Reject");
                $('#saverejectbtn').prop("disabled", false);
                $("#saverejectbtn").show();
            }
            else if(parseInt(btnInd)==3){
                $('#savewastagebtn').text("Submit Wastage");
                $('#savewastagebtn').prop("disabled", false);
                $("#savewastagebtn").show();
            }
            else if(parseInt(btnInd)==4){
                $('#saveoutputbtn').text("Close Production");
                $('#saveoutputbtn').prop("disabled", false);
                $("#saveoutputbtn").show();
            }
        }

