        function produtionTypeFn() {
            var prdtype=$('#ProductionType').val();
            var prtype = $('#ProductionType').val() == 3 ? 3 : 2;
            $('#certDynamicTable > tbody').empty();

            var gradeoptions = $("#ratiogradedefault > option").clone();
            var cropyearoption = $("#crop_year_default > option").clone();

            $('#Grade').empty();
            $('#crop_year').empty();
            if(parseInt(prdtype) == 1){
                $('.prdcertnumdiv').hide();
                $('#Grade').append(gradeoptions);
                $('#Grade').select2({
                    placeholder:"Select Grade here",
                    dropdownCssClass : 'cusprop',
                });

                $('#crop_year').append(cropyearoption);
                $('#crop_year').select2({
                    placeholder:"Select Crop year here",
                    // dropdownCssClass : 'cusprop',
                });
            }
            else if(parseInt(prdtype) == 2){
                $('.prdcertnumdiv').show();
                $('#Grade').append(gradeoptions);
                $('#Grade').select2({
                    placeholder:"Select Grade here",
                    dropdownCssClass : 'cusprop',
                });

                $('#crop_year').append(cropyearoption);
                $('#crop_year').select2({
                    placeholder:"Select Crop year here",
                    // dropdownCssClass : 'cusprop',
                });
            }
            else if(parseInt(prdtype) == 3){
                $('.prdcertnumdiv').hide();
                $('#Grade').append(`<option selected value="101">NG (No Grade)</option>`);
                $('#Grade').select2({
                    dropdownCssClass : 'cusprop',
                    minimumResultsForSearch: -1
                });

                $('#crop_year').append(`<option selected value="0">NCY(No Crop Year)</option>`);
                $('#crop_year').select2({
                    dropdownCssClass : 'cusprop',
                    minimumResultsForSearch: -1
                });
            }
            
            var defaultoption = '<option selected value=""></option>';
            var commodityoptions = $("#CommodityDefault > option").clone();
            $('#Commodity').empty();
            $('#Commodity').append(commodityoptions);
            $(`#Commodity option[title!="${prtype}"]`).remove(); 
            if(prtype == 3){
                $(`#Commodity option[value!=1]`).remove(); 
            }
            $('#Commodity').append(defaultoption);
            $('#Commodity').val(null).select2
            ({
                placeholder: "Select Commodity here",
            });
            $('#productiontype-error').html('');
        }

